a=""
b=""

def lcs(X, Y):
    m = len(X)
    n = len(Y)
    
    L = [[0] * (n + 1) for _ in range(m + 1)]
    
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if X[i-1] == Y[j-1]:
                L[i][j] = L[i-1][j-1] + 1
            else:
                L[i][j] = max(L[i-1][j], L[i][j-1])
                
    lcs_len = L[m][n]
    
    lcs_str = []
    i, j = m, n
    while i > 0 and j > 0:
        if X[i-1] == Y[j-1]:
            lcs_str.append(X[i-1])
            i -= 1
            j -= 1
        elif L[i-1][j] > L[i][j-1]:
            i -= 1
        else:
            j -= 1
            
    return lcs_len, "".join(reversed(lcs_str)), L

if __name__ == "__main__":
    length, res, table = lcs(a, b)
    print(f"Длина LCS: {length}")
    print(f"LCS: {res}")
    with open("task3_table.txt", "w") as f:
        for row in table:
            f.write(" ".join(map(str, row)) + "\n")
    print("Таблица сохранена в task3_table.txt")
